const fs = require("fs"); const path = require("path");

function w(p, c) { fs.mkdirSync(path.dirname(p), {recursive:true}); fs.writeFileSync(p, c, "utf8"); console.log("OK:", p); }

w("lib/validations/schemas.ts", "/**\n * lib/validations/schemas.ts\n * Zod schemas para todos los puntos de entrada de la aplicación.\n * Si un dato no cumple el formato, se rechaza ANTES de tocar la DB o la API.\n */\n\nimport { z } from 'zod';\n\n// ─── Helpers ───────────────────────────────────────────────────────────────────\n\nconst nonEmptyString = (field: string) =>\n  z.string({ required_error: `${field} es requerido` }).trim().min(1, `${field} no puede estar vacío`);\n\nconst safeString = (field: string, maxLen = 200) =>\n  nonEmptyString(field)\n    .max(maxLen, `${field} excede el largo máximo (${maxLen} caracteres)`)\n    .refine((v) => !/[<>'\"`;]/.test(v), `${field} contiene caracteres no permitidos`);\n\n// ─── Birth Data ───────────────────────────────────────────────────────────────\n\nexport const BirthDataSchema = z.object({\n  name: safeString('Nombre', 100),\n  email: z\n    .string({ required_error: 'Email es requerido' })\n    .trim()\n    .email('Formato de email inválido')\n    .max(254, 'Email demasiado largo')\n    .toLowerCase(),\n  birthDate: z\n    .string({ required_error: 'Fecha de nacimiento es requerida' })\n    .regex(/^\\d{4}-\\d{2}-\\d{2}$/, 'Formato de fecha inválido (YYYY-MM-DD)')\n    .refine((v) => {\n      const d = new Date(v);\n      const now = new Date();\n      const minDate = new Date('1900-01-01');\n      return d >= minDate && d <= now;\n    }, 'Fecha de nacimiento fuera de rango'),\n  birthTime: z\n    .string({ required_error: 'Hora de nacimiento es requerida' })\n    .regex(/^\\d{2}:\\d{2}(:\\d{2})?$/, 'Formato de hora inválido (HH:MM)'),\n  birthCity: safeString('Ciudad de nacimiento', 100),\n  birthCountry: safeString('País de nacimiento', 100),\n  personalContext: z\n    .string()\n    .max(1000, 'El contexto personal no puede superar 1000 caracteres')\n    .refine((v) => !/<script/i.test(v), 'Contenido no permitido')\n    .optional()\n    .nullable(),\n  language: z.enum(['es', 'en', 'pt']).default('es'),\n});\n\nexport type BirthDataInput = z.infer<typeof BirthDataSchema>;\n\n// ─── Partner Birth Data (Especial Parejas) ───────────────────────────────────\n\nexport const PartnerBirthDataSchema = BirthDataSchema.omit({ email: true, language: true }).extend({\n  name: safeString('Nombre de la pareja', 100),\n});\n\nexport type PartnerBirthDataInput = z.infer<typeof PartnerBirthDataSchema>;\n\n// ─── Checkout Request ─────────────────────────────────────────────────────────\n\nexport const CheckoutRequestSchema = z.object({\n  productSlug: z.enum(['lectura-esencial', 'consulta-evolutiva', 'especial-parejas'], {\n    errorMap: () => ({ message: 'Producto inválido' }),\n  }),\n  birthData: BirthDataSchema,\n  partnerBirthData: PartnerBirthDataSchema.optional().nullable(),\n  countryCode: z\n    .string()\n    .length(2, 'Código de país inválido')\n    .toUpperCase()\n    .default('US'),\n});\n\nexport type CheckoutRequestInput = z.infer<typeof CheckoutRequestSchema>;\n\n// ─── Mercado Pago Webhook ─────────────────────────────────────────────────────\n\nexport const MercadoPagoWebhookSchema = z.object({\n  id: z.union([z.string(), z.number()]),\n  type: z.string(),\n  action: z.string().optional(),\n  data: z\n    .object({\n      id: z.string(),\n    })\n    .optional(),\n});\n\nexport type MercadoPagoWebhookInput = z.infer<typeof MercadoPagoWebhookSchema>;\n\n// ─── Report Generation ────────────────────────────────────────────────────────\n\nexport const GenerateReportSchema = z.object({\n  transactionId: z.string().uuid('ID de transacción inválido'),\n});\n\nexport type GenerateReportInput = z.infer<typeof GenerateReportSchema>;\n\n// ─── Environment Variable Validation ─────────────────────────────────────────\n/**\n * Valida que todas las variables de entorno críticas estén presentes en el servidor.\n * Lanza un error en tiempo de build/arranque si falta alguna.\n * NUNCA exponer al cliente — solo llamar desde código server-side.\n */\nexport function validateServerEnv(): void {\n  const required: Record<string, string | undefined> = {\n    NEXT_PUBLIC_SUPABASE_URL: process.env.NEXT_PUBLIC_SUPABASE_URL,\n    NEXT_PUBLIC_SUPABASE_ANON_KEY: process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY,\n    SUPABASE_SERVICE_ROLE_KEY: process.env.SUPABASE_SERVICE_ROLE_KEY,\n    GEMINI_API_KEY: process.env.GEMINI_API_KEY,\n    MERCADOPAGO_ACCESS_TOKEN: process.env.MERCADOPAGO_ACCESS_TOKEN,\n    MERCADOPAGO_WEBHOOK_SECRET: process.env.MERCADOPAGO_WEBHOOK_SECRET,\n  };\n\n  const missing = Object.entries(required)\n    .filter(([, v]) => !v || v.trim() === '')\n    .map(([k]) => k);\n\n  if (missing.length > 0) {\n    throw new Error(\n      `[Astral Evolution] Variables de entorno faltantes: ${missing.join(', ')}.\\n` +\n      'Agrega estas variables en el dashboard de Vercel antes de hacer deploy.'\n    );\n  }\n\n  // Detectar saltos de línea invisibles (problema reportado con echo en Vercel)\n  const hasLineBreaks = Object.entries(required).filter(\n    ([, v]) => v && /[\\r\\n]/.test(v)\n  );\n  if (hasLineBreaks.length > 0) {\n    throw new Error(\n      `[Astral Evolution] Variables con saltos de línea detectados: ${hasLineBreaks.map(([k]) => k).join(', ')}.\\n` +\n      'Usa el dashboard web de Vercel para recargarlas (NO usar echo en CLI).'\n    );\n  }\n}\n\n// ─── Output Sanitizer (para reportes de IA) ──────────────────────────────────\n\n/**\n * Sanitiza el texto generado por Gemini antes de renderizarlo en el DOM.\n * Elimina tags HTML, scripts y caracteres de control peligrosos.\n */\nexport function sanitizeAIOutput(raw: string): string {\n  return raw\n    // Eliminar tags HTML/script\n    .replace(/<script[\\s\\S]*?>[\\s\\S]*?<\\/script>/gi, '')\n    .replace(/<style[\\s\\S]*?>[\\s\\S]*?<\\/style>/gi, '')\n    .replace(/<[^>]+>/g, '')\n    // Eliminar inyecciones de protocolo\n    .replace(/javascript:/gi, '')\n    .replace(/vbscript:/gi, '')\n    .replace(/data:text\\/html/gi, '')\n    // Escapar entidades HTML básicas\n    .replace(/&/g, '&amp;')\n    .replace(/</g, '&lt;')\n    .replace(/>/g, '&gt;')\n    .replace(/\"/g, '&quot;')\n    .replace(/'/g, '&#x27;')\n    // Eliminar caracteres de control (excepto saltos de línea y tabs)\n    // eslint-disable-next-line no-control-regex\n    .replace(/[\\x00-\\x08\\x0B\\x0C\\x0E-\\x1F\\x7F]/g, '')\n    .trim();\n}\n");
w("lib/email/send-report.ts", "/**\n * lib/email/send-report.ts\n * Email del reporte astrológico — diseño premium oscuro, consistente con astralevolution.com\n */\n\nexport interface ReportEmailData {\n  toEmail: string;\n  toName: string;\n  productName: string;\n  productSlug: string;\n  reportContent: string;\n  transactionId: string;\n}\n\n// Convierte **negrita** y saltos de línea a HTML seguro para email\nfunction markdownToEmailHTML(text: string): string {\n  return text\n    .split('\\n\\n')\n    .map((paragraph) => {\n      const withBold = paragraph\n        .trim()\n        .replace(/\\*\\*(.+?)\\*\\*/g, '<strong style=\"color:#c4b5fd;font-weight:600;\">$1</strong>');\n      // Si el párrafo empieza con un título en negrita, renderizar como sección\n      if (withBold.startsWith('<strong')) {\n        return `\n          <div style=\"margin-bottom:28px;\">\n            <div style=\"margin-bottom:10px;padding-bottom:8px;border-bottom:1px solid rgba(139,92,246,0.2);\">\n              ${withBold.replace(/<\\/strong>.*/, '</strong>')}\n            </div>\n            <p style=\"color:#d1d5db;font-size:15px;line-height:1.85;margin:0;\">\n              ${withBold.replace(/^<strong[^>]*>[^<]+<\\/strong>\\s*—?\\s*/, '')}\n            </p>\n          </div>`;\n      }\n      return `<p style=\"color:#d1d5db;font-size:15px;line-height:1.85;margin:0 0 20px;\">${withBold}</p>`;\n    })\n    .join('');\n}\n\nconst PRODUCT_ICONS: Record<string, string> = {\n  'lectura-esencial': '🌙',\n  'consulta-evolutiva': '⭐',\n  'especial-parejas': '✨',\n};\n\nconst PRODUCT_COLORS: Record<string, { primary: string; secondary: string; glow: string }> = {\n  'lectura-esencial': {\n    primary: 'rgba(139,92,246,0.6)',\n    secondary: 'rgba(99,102,241,0.3)',\n    glow: '139,92,246',\n  },\n  'consulta-evolutiva': {\n    primary: 'rgba(59,130,246,0.6)',\n    secondary: 'rgba(99,102,241,0.3)',\n    glow: '59,130,246',\n  },\n  'especial-parejas': {\n    primary: 'rgba(236,72,153,0.5)',\n    secondary: 'rgba(139,92,246,0.3)',\n    glow: '236,72,153',\n  },\n};\n\nexport function buildReportEmailHTML(data: ReportEmailData): string {\n  const icon = PRODUCT_ICONS[data.productSlug] ?? '🌟';\n  const colors = PRODUCT_COLORS[data.productSlug] ?? PRODUCT_COLORS['lectura-esencial'];\n  const reportHTML = markdownToEmailHTML(data.reportContent);\n  const year = new Date().getFullYear();\n\n  return `<!DOCTYPE html>\n<html lang=\"es\" xmlns=\"http://www.w3.org/1999/xhtml\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <meta http-equiv=\"X-UA-Compatible\" content=\"IE=edge\">\n  <title>${data.productName} · Astral Evolution</title>\n  <!--[if mso]>\n  <noscript><xml><o:OfficeDocumentSettings><o:PixelsPerInch>96</o:PixelsPerInch></o:OfficeDocumentSettings></xml></noscript>\n  <![endif]-->\n</head>\n<body style=\"margin:0;padding:0;background-color:#06060f;-webkit-font-smoothing:antialiased;\">\n\n<!-- Wrapper -->\n<table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"background-color:#06060f;min-height:100vh;\">\n  <tr>\n    <td align=\"center\" style=\"padding:40px 16px 60px;\">\n\n      <!-- Card principal -->\n      <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"max-width:620px;\">\n\n        <!-- ─── HEADER ─────────────────────────────────────── -->\n        <tr>\n          <td style=\"padding-bottom:0;\">\n            <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\"\n              style=\"background:linear-gradient(160deg,#0f0a1e 0%,#0a0818 50%,#0d0a20 100%);border-radius:24px 24px 0 0;border:1px solid rgba(139,92,246,0.25);border-bottom:none;overflow:hidden;\">\n              <tr>\n                <td style=\"padding:48px 40px 36px;text-align:center;\">\n\n                  <!-- Logo / marca -->\n                  <div style=\"margin-bottom:28px;\">\n                    <span style=\"display:inline-block;padding:8px 20px;border-radius:50px;background:rgba(139,92,246,0.12);border:1px solid rgba(139,92,246,0.3);color:#a78bfa;font-family:Georgia,serif;font-size:12px;letter-spacing:3px;text-transform:uppercase;\">\n                      ✦ Astral Evolution ✦\n                    </span>\n                  </div>\n\n                  <!-- Ícono del producto -->\n                  <div style=\"margin-bottom:20px;\">\n                    <div style=\"display:inline-block;width:72px;height:72px;border-radius:50%;background:linear-gradient(135deg,${colors.primary},${colors.secondary});border:1px solid rgba(${colors.glow},0.4);font-size:32px;line-height:72px;text-align:center;\">\n                      ${icon}\n                    </div>\n                  </div>\n\n                  <!-- Título -->\n                  <h1 style=\"margin:0 0 12px;font-family:Georgia,serif;font-size:28px;font-weight:normal;color:#f9fafb;letter-spacing:-0.5px;\">\n                    Tu ${data.productName}\n                  </h1>\n                  <p style=\"margin:0;font-family:Arial,sans-serif;font-size:16px;color:#9ca3af;\">\n                    preparada especialmente para\n                    <span style=\"color:#c4b5fd;font-style:italic;\"> ${data.toName}</span>\n                  </p>\n\n                  <!-- Separador decorativo -->\n                  <div style=\"margin:28px auto 0;max-width:200px;height:1px;background:linear-gradient(90deg,transparent,rgba(139,92,246,0.5),transparent);\"></div>\n\n                </td>\n              </tr>\n            </table>\n          </td>\n        </tr>\n\n        <!-- ─── INTRO ───────────────────────────────────────── -->\n        <tr>\n          <td>\n            <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\"\n              style=\"background:#0d0b1a;border-left:1px solid rgba(139,92,246,0.25);border-right:1px solid rgba(139,92,246,0.25);\">\n              <tr>\n                <td style=\"padding:24px 40px;\">\n                  <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\"\n                    style=\"background:rgba(139,92,246,0.08);border:1px solid rgba(139,92,246,0.2);border-radius:12px;\">\n                    <tr>\n                      <td style=\"padding:20px 24px;\">\n                        <p style=\"margin:0;font-family:Georgia,serif;font-size:15px;color:#c4b5fd;line-height:1.7;font-style:italic;\">\n                          \"Las estrellas no determinan tu destino — lo iluminan.\n                          Esta lectura es tu mapa del cielo interior.\"\n                        </p>\n                      </td>\n                    </tr>\n                  </table>\n                </td>\n              </tr>\n            </table>\n          </td>\n        </tr>\n\n        <!-- ─── SEPARADOR ──────────────────────────────────── -->\n        <tr>\n          <td>\n            <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\"\n              style=\"background:#0d0b1a;border-left:1px solid rgba(139,92,246,0.25);border-right:1px solid rgba(139,92,246,0.25);\">\n              <tr>\n                <td style=\"padding:4px 40px 0;\">\n                  <div style=\"height:1px;background:linear-gradient(90deg,transparent,rgba(139,92,246,0.3),transparent);\"></div>\n                </td>\n              </tr>\n            </table>\n          </td>\n        </tr>\n\n        <!-- ─── CONTENIDO DEL REPORTE ───────────────────────── -->\n        <tr>\n          <td>\n            <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\"\n              style=\"background:#0d0b1a;border-left:1px solid rgba(139,92,246,0.25);border-right:1px solid rgba(139,92,246,0.25);\">\n              <tr>\n                <td style=\"padding:36px 40px;\">\n                  ${reportHTML}\n                </td>\n              </tr>\n            </table>\n          </td>\n        </tr>\n\n        <!-- ─── CTA ────────────────────────────────────────── -->\n        <tr>\n          <td>\n            <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\"\n              style=\"background:#0d0b1a;border-left:1px solid rgba(139,92,246,0.25);border-right:1px solid rgba(139,92,246,0.25);\">\n              <tr>\n                <td style=\"padding:8px 40px 40px;text-align:center;\">\n                  <div style=\"height:1px;background:linear-gradient(90deg,transparent,rgba(139,92,246,0.3),transparent);margin-bottom:32px;\"></div>\n                  <p style=\"margin:0 0 20px;font-family:Arial,sans-serif;font-size:14px;color:#6b7280;\">\n                    ¿Querés profundizar aún más en tu camino?\n                  </p>\n                  <a href=\"https://astralevolution.com/#productos\"\n                    style=\"display:inline-block;padding:14px 32px;border-radius:50px;background:linear-gradient(135deg,rgba(139,92,246,0.8),rgba(99,102,241,0.8));color:#ffffff;font-family:Arial,sans-serif;font-size:14px;font-weight:600;text-decoration:none;letter-spacing:0.5px;\">\n                    ✨ Explorar más lecturas\n                  </a>\n                </td>\n              </tr>\n            </table>\n          </td>\n        </tr>\n\n        <!-- ─── FOOTER ─────────────────────────────────────── -->\n        <tr>\n          <td>\n            <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\"\n              style=\"background:#090714;border-radius:0 0 24px 24px;border:1px solid rgba(139,92,246,0.15);border-top:none;overflow:hidden;\">\n              <tr>\n                <td style=\"padding:28px 40px;text-align:center;\">\n                  <p style=\"margin:0 0 8px;font-family:Arial,sans-serif;font-size:13px;color:#4b5563;\">\n                    ¿Preguntas? Respondé este email o escribinos a\n                    <a href=\"mailto:contacto@astralevolution.com\" style=\"color:#7c3aed;text-decoration:none;\">contacto@astralevolution.com</a>\n                  </p>\n                  <p style=\"margin:0;font-family:Arial,sans-serif;font-size:11px;color:#374151;\">\n                    Ref: ${data.transactionId} · © ${year} Astral Evolution · Todos los derechos reservados\n                  </p>\n                  <p style=\"margin:8px 0 0;font-family:Arial,sans-serif;font-size:11px;color:#374151;\">\n                    <a href=\"https://astralevolution.com\" style=\"color:#6b21a8;text-decoration:none;\">astralevolution.com</a>\n                  </p>\n                </td>\n              </tr>\n            </table>\n          </td>\n        </tr>\n\n      </table>\n      <!-- fin card -->\n\n    </td>\n  </tr>\n</table>\n\n</body>\n</html>`;\n}\n\n// ─── Función principal de envío ───────────────────────────────────────────────\nexport async function sendReportEmail(data: ReportEmailData): Promise<{ success: boolean; error?: string }> {\n  const apiKey = process.env.RESEND_API_KEY?.trim();\n  if (!apiKey) {\n    console.warn('[Email] RESEND_API_KEY no configurada');\n    return { success: false, error: 'RESEND_API_KEY no configurada' };\n  }\n\n  const fromAddress = process.env.EMAIL_FROM?.trim() ?? 'lecturas@astralevolution.com';\n\n  try {\n    const res = await fetch('https://api.resend.com/emails', {\n      method: 'POST',\n      headers: {\n        Authorization: `Bearer ${apiKey}`,\n        'Content-Type': 'application/json',\n      },\n      body: JSON.stringify({\n        from: `Astral Evolution <${fromAddress}>`,\n        to: [data.toEmail],\n        subject: `${PRODUCT_ICONS[data.productSlug] ?? '✨'} Tu ${data.productName} está lista, ${data.toName}`,\n        html: buildReportEmailHTML(data),\n        tags: [\n          { name: 'category', value: 'report' },\n          { name: 'product', value: data.productSlug },\n        ],\n      }),\n    });\n\n    if (!res.ok) {\n      const err = await res.text();\n      console.error('[Email] Error Resend:', err);\n      return { success: false, error: err };\n    }\n\n    const result = await res.json();\n    console.log('[Email] Enviado OK, id:', result.id);\n    return { success: true };\n  } catch (err) {\n    const msg = err instanceof Error ? err.message : 'Error desconocido';\n    console.error('[Email] Error de red:', msg);\n    return { success: false, error: msg };\n  }\n}\n");
w("lib/email/send-birthday.ts", "/**\n * lib/email/send-birthday.ts\n * Email de cumpleaños con mini análisis de Revolución Solar.\n * Se envía automáticamente el día del cumpleaños de cada cliente.\n * Incluye 2-3 revelaciones del año + CTA para comprar el análisis completo.\n */\n\nexport interface BirthdayEmailData {\n  toEmail: string;\n  toName: string;\n  birthDate: string;       // \"YYYY-MM-DD\"\n  birthCity: string;\n  birthCountry: string;\n  miniAnalysis: string;    // Generado por Gemini, ya sanitizado\n  userId: string;\n}\n\nexport function buildBirthdayEmailHTML(data: BirthdayEmailData): string {\n  const year = new Date().getFullYear();\n\n  // Formato: \"15 de abril\"\n  const [, , day] = data.birthDate.split('-');\n  const monthNames = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];\n  const birthMonth = new Date(data.birthDate).getMonth();\n  const birthdayFormatted = `${parseInt(day)} de ${monthNames[birthMonth]}`;\n\n  // Mini análisis: convertir **negrita** a HTML\n  const analysisHTML = data.miniAnalysis\n    .replace(/\\*\\*(.+?)\\*\\*/g, '<strong style=\"color:#fbbf24;\">$1</strong>')\n    .split('\\n\\n')\n    .map(p => `<p style=\"margin:0 0 16px;font-family:Georgia,serif;font-size:15px;color:#e5e7eb;line-height:1.8;\">${p.trim()}</p>`)\n    .join('');\n\n  return `<!DOCTYPE html>\n<html lang=\"es\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>¡Feliz Cumpleaños, ${data.toName}! · Astral Evolution</title>\n</head>\n<body style=\"margin:0;padding:0;background-color:#06060f;\">\n\n<table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"background-color:#06060f;min-height:100vh;\">\n  <tr>\n    <td align=\"center\" style=\"padding:40px 16px 60px;\">\n      <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"max-width:620px;\">\n\n        <!-- ─── HEADER DE CUMPLEAÑOS ──────────────────────── -->\n        <tr>\n          <td>\n            <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\"\n              style=\"background:linear-gradient(160deg,#12080a 0%,#0f0a1e 60%,#120810 100%);border-radius:24px 24px 0 0;border:1px solid rgba(251,191,36,0.2);border-bottom:none;\">\n              <tr>\n                <td style=\"padding:48px 40px 36px;text-align:center;\">\n\n                  <div style=\"margin-bottom:24px;\">\n                    <span style=\"display:inline-block;padding:8px 20px;border-radius:50px;background:rgba(251,191,36,0.1);border:1px solid rgba(251,191,36,0.3);color:#fcd34d;font-family:Arial,sans-serif;font-size:12px;letter-spacing:3px;text-transform:uppercase;\">\n                      ✦ Astral Evolution ✦\n                    </span>\n                  </div>\n\n                  <!-- Emoji animado cumpleaños -->\n                  <div style=\"font-size:52px;margin-bottom:20px;line-height:1;\">🎂</div>\n\n                  <h1 style=\"margin:0 0 8px;font-family:Georgia,serif;font-size:30px;font-weight:normal;color:#f9fafb;\">\n                    ¡Feliz Cumpleaños,<br>\n                    <em style=\"color:#fcd34d;\">${data.toName}</em>!\n                  </h1>\n                  <p style=\"margin:12px 0 0;font-family:Arial,sans-serif;font-size:15px;color:#9ca3af;\">\n                    Hoy, ${birthdayFormatted}, el Sol vuelve exactamente al lugar donde estaba cuando llegaste al mundo.\n                    <br>Eso se llama <strong style=\"color:#fbbf24;\">Revolución Solar</strong> — y este año tiene mensajes únicos para vos.\n                  </p>\n\n                  <div style=\"margin:28px auto 0;max-width:200px;height:1px;background:linear-gradient(90deg,transparent,rgba(251,191,36,0.4),transparent);\"></div>\n\n                </td>\n              </tr>\n            </table>\n          </td>\n        </tr>\n\n        <!-- ─── SECCIÓN: LO QUE VIENE ESTE AÑO ──────────── -->\n        <tr>\n          <td>\n            <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\"\n              style=\"background:#0d0b1a;border-left:1px solid rgba(251,191,36,0.15);border-right:1px solid rgba(251,191,36,0.15);\">\n              <tr>\n                <td style=\"padding:32px 40px;\">\n\n                  <!-- Título de sección -->\n                  <table cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\" style=\"margin-bottom:24px;\">\n                    <tr>\n                      <td>\n                        <div style=\"display:inline-block;padding:6px 14px;border-radius:8px;background:rgba(251,191,36,0.1);border:1px solid rgba(251,191,36,0.25);\">\n                          <span style=\"font-family:Arial,sans-serif;font-size:12px;color:#fcd34d;letter-spacing:1px;text-transform:uppercase;font-weight:600;\">\n                            🔮 Tu año ${year} — ${year + 1}\n                          </span>\n                        </div>\n                      </td>\n                    </tr>\n                  </table>\n\n                  <!-- Mini análisis -->\n                  ${analysisHTML}\n\n                </td>\n              </tr>\n            </table>\n          </td>\n        </tr>\n\n        <!-- ─── CTA: VER EL ANÁLISIS COMPLETO ────────────── -->\n        <tr>\n          <td>\n            <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\"\n              style=\"background:#0d0b1a;border-left:1px solid rgba(251,191,36,0.15);border-right:1px solid rgba(251,191,36,0.15);\">\n              <tr>\n                <td style=\"padding:0 40px 40px;\">\n\n                  <!-- Card de upgrade -->\n                  <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\"\n                    style=\"background:linear-gradient(135deg,rgba(251,191,36,0.08),rgba(139,92,246,0.08));border:1px solid rgba(251,191,36,0.25);border-radius:16px;\">\n                    <tr>\n                      <td style=\"padding:28px 28px 24px;text-align:center;\">\n                        <p style=\"margin:0 0 6px;font-family:Georgia,serif;font-size:18px;color:#f9fafb;\">\n                          Esto es solo el comienzo 🌟\n                        </p>\n                        <p style=\"margin:0 0 20px;font-family:Arial,sans-serif;font-size:14px;color:#9ca3af;line-height:1.6;\">\n                          Tu Revolución Solar completa incluye el análisis de todas las casas activadas, los tránsitos del año, tus ciclos personales y un plan mes a mes. 10-15 páginas dedicadas únicamente a vos.\n                        </p>\n                        <a href=\"https://astralevolution.com/productos/consulta-evolutiva\"\n                          style=\"display:inline-block;padding:14px 32px;border-radius:50px;background:linear-gradient(135deg,#d97706,#b45309);color:#ffffff;font-family:Arial,sans-serif;font-size:14px;font-weight:700;text-decoration:none;letter-spacing:0.5px;\">\n                          🎁 Ver mi análisis completo →\n                        </a>\n                        <p style=\"margin:16px 0 0;font-family:Arial,sans-serif;font-size:12px;color:#6b7280;\">\n                          Como cliente anterior, tenés acceso prioritario. Sin filas.\n                        </p>\n                      </td>\n                    </tr>\n                  </table>\n\n                </td>\n              </tr>\n            </table>\n          </td>\n        </tr>\n\n        <!-- ─── FOOTER ─────────────────────────────────────── -->\n        <tr>\n          <td>\n            <table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\"\n              style=\"background:#090714;border-radius:0 0 24px 24px;border:1px solid rgba(251,191,36,0.1);border-top:none;\">\n              <tr>\n                <td style=\"padding:24px 40px;text-align:center;\">\n                  <p style=\"margin:0 0 8px;font-family:Arial,sans-serif;font-size:13px;color:#4b5563;\">\n                    Este regalo astral llega porque alguna vez confiaste en nosotros. Gracias 🙏\n                  </p>\n                  <p style=\"margin:0;font-family:Arial,sans-serif;font-size:11px;color:#374151;\">\n                    © ${year} Astral Evolution ·\n                    <a href=\"https://astralevolution.com\" style=\"color:#6b21a8;text-decoration:none;\">astralevolution.com</a>\n                  </p>\n                </td>\n              </tr>\n            </table>\n          </td>\n        </tr>\n\n      </table>\n    </td>\n  </tr>\n</table>\n\n</body>\n</html>`;\n}\n\n// ─── Envío del email de cumpleaños ────────────────────────────────────────────\nexport async function sendBirthdayEmail(data: BirthdayEmailData): Promise<{ success: boolean; error?: string }> {\n  const apiKey = process.env.RESEND_API_KEY?.trim();\n  if (!apiKey) return { success: false, error: 'RESEND_API_KEY no configurada' };\n\n  const fromAddress = process.env.EMAIL_FROM?.trim() ?? 'lecturas@astralevolution.com';\n\n  try {\n    const res = await fetch('https://api.resend.com/emails', {\n      method: 'POST',\n      headers: {\n        Authorization: `Bearer ${apiKey}`,\n        'Content-Type': 'application/json',\n      },\n      body: JSON.stringify({\n        from: `Astral Evolution <${fromAddress}>`,\n        to: [data.toEmail],\n        subject: `🎂 ¡Feliz cumpleaños, ${data.toName}! Tu año astrológico te espera`,\n        html: buildBirthdayEmailHTML(data),\n        tags: [\n          { name: 'category', value: 'birthday' },\n        ],\n      }),\n    });\n\n    if (!res.ok) {\n      const err = await res.text();\n      return { success: false, error: err };\n    }\n\n    console.log(`[Birthday Email] Enviado a ${data.toEmail}`);\n    return { success: true };\n  } catch (err) {\n    return { success: false, error: err instanceof Error ? err.message : 'Error desconocido' };\n  }\n}\n");
w("lib/seo/metadata.ts", "/**\n * lib/seo/metadata.ts\n * SEO localizado por país/región con las palabras que realmente busca cada mercado.\n * \n * Investigación de términos por país:\n * - AR/UY: \"carta natal gratis\", \"lectura astral\", \"astrología evolutiva\", \"carta natal online\"\n * - MX: \"carta astral\", \"horóscopo personalizado\", \"carta natal gratuita\"\n * - CO/VE/PE: \"carta natal\", \"horóscopo de hoy\", \"lectura del tarot\" (competencia)\n * - CL: \"carta natal chilena\", \"astrología online\", \"revolución solar\"\n * - ES: \"carta natal\", \"astrólogo online\", \"lectura astrológica\"\n * - US (en español): \"birth chart reading\", \"astrology reading online\"\n */\n\nimport type { Metadata } from 'next';\n\n// ─── Textos base por idioma/región ────────────────────────────────────────────\n\nconst SEO_BY_REGION = {\n  // ── Argentina / Uruguay ──────────────────────────────────────────────────\n  'ar-uy': {\n    siteName: 'Astral Evolution',\n    title: 'Astral Evolution — Carta Natal y Lectura Astrológica con IA',\n    titleTemplate: '%s | Astral Evolution — Astrología Evolutiva',\n    description:\n      'Obtené tu carta natal personalizada con inteligencia artificial. Análisis profundo de tu Sol, Luna, Ascendente y tránsitos. Entrega en minutos. Astrología evolutiva para tu crecimiento personal.',\n    keywords: [\n      'carta natal online',\n      'lectura astral personalizada',\n      'astrología evolutiva Argentina',\n      'carta natal gratis',\n      'carta natal con IA',\n      'análisis astrológico personalizado',\n      'revolución solar',\n      'sinastría pareja',\n      'tránsitos astrológicos',\n      'astrólogo online Uruguay',\n      'lectura astrológica online',\n      'carta natal 2025',\n      'casa natal astrología',\n      'quirón herida primordial',\n      'nodos lunares',\n    ],\n    ogLocale: 'es_AR',\n  },\n\n  // ── México ────────────────────────────────────────────────────────────────\n  'mx': {\n    siteName: 'Astral Evolution',\n    title: 'Astral Evolution — Carta Astral y Lectura Astrológica con IA',\n    titleTemplate: '%s | Astral Evolution — Tu Carta Astral',\n    description:\n      'Descubre tu carta astral personalizada con inteligencia artificial. Análisis completo de tu Sol, Luna y Ascendente con los tránsitos actuales. Entrega en minutos desde cualquier lugar de México.',\n    keywords: [\n      'carta astral México',\n      'carta natal gratuita',\n      'lectura astrológica online',\n      'horóscopo personalizado',\n      'carta astral con inteligencia artificial',\n      'astrología evolutiva',\n      'astrólogo online México',\n      'revolución solar análisis',\n      'compatibilidad astrológica pareja',\n      'lectura de carta natal 2025',\n      'tránsitos planetarios',\n      'nodos lunares propósito de vida',\n    ],\n    ogLocale: 'es_MX',\n  },\n\n  // ── Colombia / Venezuela / Perú ───────────────────────────────────────────\n  'co-ve-pe': {\n    siteName: 'Astral Evolution',\n    title: 'Astral Evolution — Lectura Astrológica Personalizada con IA',\n    titleTemplate: '%s | Astral Evolution — Astrología Online',\n    description:\n      'Tu carta natal y lectura astrológica generada con inteligencia artificial. Descubre tu propósito, tus talentos y los ciclos que marcan tu vida. Entrega inmediata online.',\n    keywords: [\n      'carta natal online Colombia',\n      'lectura astrológica personalizada',\n      'astrología online',\n      'carta natal inteligencia artificial',\n      'horóscopo natal',\n      'astrólogo online',\n      'compatibilidad astrológica',\n      'lectura del cielo natal',\n      'análisis astrológico 2025',\n      'revolución solar',\n    ],\n    ogLocale: 'es_CO',\n  },\n\n  // ── Chile ─────────────────────────────────────────────────────────────────\n  'cl': {\n    siteName: 'Astral Evolution',\n    title: 'Astral Evolution — Carta Natal y Astrología Evolutiva Online',\n    titleTemplate: '%s | Astral Evolution — Astrología Chile',\n    description:\n      'Obtén tu carta natal completa y análisis astrológico evolutivo generado con IA. Sol, Luna, Ascendente, tránsitos y revolución solar. Entrega en minutos. Astrólogos online en Chile y todo el mundo.',\n    keywords: [\n      'carta natal Chile',\n      'lectura astrológica online Chile',\n      'astrología evolutiva',\n      'astrólogo online Chile',\n      'carta natal con IA',\n      'revolución solar Chile',\n      'análisis natal personalizado',\n      'compatibilidad de pareja astrología',\n    ],\n    ogLocale: 'es_CL',\n  },\n\n  // ── España ────────────────────────────────────────────────────────────────\n  'es': {\n    siteName: 'Astral Evolution',\n    title: 'Astral Evolution — Carta Natal y Lectura Astrológica con IA',\n    titleTemplate: '%s | Astral Evolution — Astrología Evolutiva España',\n    description:\n      'Obtén tu carta natal y lectura astrológica personalizada generada con inteligencia artificial. Análisis profundo de tu Sol, Luna, Ascendente y ciclos planetarios. Entrega inmediata.',\n    keywords: [\n      'carta natal España',\n      'lectura astrológica online',\n      'astrólogo online',\n      'carta natal con inteligencia artificial',\n      'astrología evolutiva España',\n      'análisis astrológico personalizado',\n      'revolución solar',\n      'sinastría pareja',\n      'tránsitos 2025',\n      'carta natal 2025 España',\n    ],\n    ogLocale: 'es_ES',\n  },\n\n  // ── EEUU (español) ────────────────────────────────────────────────────────\n  'us-es': {\n    siteName: 'Astral Evolution',\n    title: 'Astral Evolution — Birth Chart & Astrology Reading with AI',\n    titleTemplate: '%s | Astral Evolution — AI Astrology',\n    description:\n      'Get your personalized birth chart and astrology reading generated by AI. Deep analysis of your Sun, Moon, Rising and current transits. Delivered in minutes.',\n    keywords: [\n      'birth chart reading online',\n      'astrology reading AI',\n      'natal chart analysis',\n      'personalized horoscope',\n      'evolutionary astrology',\n      'birth chart AI',\n      'solar return reading',\n      'synastry compatibility',\n      'astrologer online',\n      'birth chart 2025',\n    ],\n    ogLocale: 'en_US',\n  },\n\n  // ── Default (fallback) ────────────────────────────────────────────────────\n  'default': {\n    siteName: 'Astral Evolution',\n    title: 'Astral Evolution — Carta Natal y Lectura Astrológica con IA',\n    titleTemplate: '%s | Astral Evolution',\n    description:\n      'Tu carta natal y lectura astrológica personalizada generada con inteligencia artificial. Análisis profundo de tu Sol, Luna y Ascendente. Entrega inmediata.',\n    keywords: [\n      'carta natal',\n      'lectura astrológica',\n      'astrología evolutiva',\n      'astrólogo online',\n      'carta natal con IA',\n      'revolución solar',\n    ],\n    ogLocale: 'es_ES',\n  },\n} as const;\n\n// ─── Metadata base para Next.js app router ────────────────────────────────────\n\nexport const BASE_URL = 'https://astralevolution.com';\n\nexport function getBaseMetadata(region: keyof typeof SEO_BY_REGION = 'default'): Metadata {\n  const seo = SEO_BY_REGION[region] ?? SEO_BY_REGION['default'];\n\n  return {\n    metadataBase: new URL(BASE_URL),\n    title: {\n      default: seo.title,\n      template: seo.titleTemplate,\n    },\n    description: seo.description,\n    keywords: seo.keywords,\n    authors: [{ name: 'Astral Evolution', url: BASE_URL }],\n    creator: 'Astral Evolution',\n    publisher: 'Astral Evolution',\n    robots: {\n      index: true,\n      follow: true,\n      googleBot: { index: true, follow: true, 'max-image-preview': 'large' },\n    },\n    openGraph: {\n      type: 'website',\n      siteName: seo.siteName,\n      title: seo.title,\n      description: seo.description,\n      url: BASE_URL,\n      locale: seo.ogLocale,\n      images: [\n        {\n          url: `${BASE_URL}/og-image.jpg`,\n          width: 1200,\n          height: 630,\n          alt: 'Astral Evolution — Lectura Astrológica con IA',\n        },\n      ],\n    },\n    twitter: {\n      card: 'summary_large_image',\n      title: seo.title,\n      description: seo.description,\n      images: [`${BASE_URL}/og-image.jpg`],\n      creator: '@astralevolution',\n    },\n    alternates: {\n      canonical: BASE_URL,\n    },\n    icons: {\n      icon: '/favicon.ico',\n      apple: '/apple-touch-icon.png',\n    },\n  };\n}\n\n// ─── Metadata por producto ────────────────────────────────────────────────────\n\nexport const PRODUCT_METADATA: Record<string, { title: string; description: string; keywords: string[] }> = {\n  'lectura-esencial': {\n    title: 'Lectura Esencial — Sol, Luna y Ascendente con IA',\n    description:\n      'Análisis completo de tu Sol, Luna y Ascendente con los tránsitos del mes actual. El punto de partida ideal para conocer tu mapa astrológico. Entrega en 10-15 minutos.',\n    keywords: [\n      'lectura esencial astrológica',\n      'análisis sol luna ascendente',\n      'tránsitos del mes astrología',\n      'carta natal básica',\n      'lectura astrológica económica',\n    ],\n  },\n  'consulta-evolutiva': {\n    title: 'Consulta Evolutiva — Carta Natal Completa 10-15 páginas',\n    description:\n      'Tu carta natal completa: todos los planetas, las 12 casas, nodos lunares, Quirón, tránsitos anuales y revolución solar. El análisis astrológico más profundo. Entrega en 20-30 minutos.',\n    keywords: [\n      'carta natal completa',\n      'consulta astrológica evolutiva',\n      'análisis carta natal profundo',\n      'revolución solar análisis',\n      'nodos lunares karma',\n      'quirón sanación',\n      'tránsitos anuales',\n    ],\n  },\n  'especial-parejas': {\n    title: 'Especial Parejas — Sinastría Completa con IA',\n    description:\n      'Análisis completo de sinastría: compatibilidad, dinámicas relacionales, fortalezas y desafíos de tu pareja. Descubre el propósito de vuestra relación. Entrega en 25-35 minutos.',\n    keywords: [\n      'sinastría pareja astrología',\n      'compatibilidad astrológica pareja',\n      'análisis relacional carta natal',\n      'sinastría online',\n      'compatibilidad sol luna ascendente pareja',\n    ],\n  },\n};\n\n// ─── JSON-LD Structured Data ──────────────────────────────────────────────────\n\nexport function getOrganizationSchema() {\n  return {\n    '@context': 'https://schema.org',\n    '@type': 'Organization',\n    name: 'Astral Evolution',\n    url: BASE_URL,\n    logo: `${BASE_URL}/logo.png`,\n    description: 'Plataforma de lecturas astrológicas personalizadas generadas con inteligencia artificial.',\n    contactPoint: {\n      '@type': 'ContactPoint',\n      email: 'contacto@astralevolution.com',\n      contactType: 'customer service',\n      availableLanguage: ['Spanish', 'English', 'Portuguese'],\n    },\n    sameAs: [\n      'https://www.instagram.com/astralevolution',\n    ],\n  };\n}\n\nexport function getProductSchema(slug: string, price: number) {\n  const meta = PRODUCT_METADATA[slug];\n  if (!meta) return null;\n\n  return {\n    '@context': 'https://schema.org',\n    '@type': 'Product',\n    name: meta.title,\n    description: meta.description,\n    url: `${BASE_URL}/productos/${slug}`,\n    image: `${BASE_URL}/og-${slug}.jpg`,\n    brand: { '@type': 'Brand', name: 'Astral Evolution' },\n    offers: {\n      '@type': 'Offer',\n      price: price.toFixed(2),\n      priceCurrency: 'USD',\n      availability: 'https://schema.org/InStock',\n      seller: { '@type': 'Organization', name: 'Astral Evolution' },\n    },\n  };\n}\n\nexport function getFAQSchema() {\n  return {\n    '@context': 'https://schema.org',\n    '@type': 'FAQPage',\n    mainEntity: [\n      {\n        '@type': 'Question',\n        name: '¿Qué es una carta natal?',\n        acceptedAnswer: {\n          '@type': 'Answer',\n          text: 'Una carta natal es un mapa del cielo en el momento exacto de tu nacimiento. Muestra la posición del Sol, la Luna y los planetas, revelando tu personalidad, talentos y propósito de vida.',\n        },\n      },\n      {\n        '@type': 'Question',\n        name: '¿Cómo se genera la lectura?',\n        acceptedAnswer: {\n          '@type': 'Answer',\n          text: 'Usamos inteligencia artificial avanzada (Google Gemini) para generar un análisis profundo y personalizado basado en los datos exactos de tu nacimiento. La entrega es en minutos.',\n        },\n      },\n      {\n        '@type': 'Question',\n        name: '¿Cuánto tarda en llegar?',\n        acceptedAnswer: {\n          '@type': 'Answer',\n          text: 'La Lectura Esencial llega en 10-15 minutos, la Consulta Evolutiva en 20-30 minutos, y el Especial Parejas en 25-35 minutos. Siempre a tu email.',\n        },\n      },\n      {\n        '@type': 'Question',\n        name: '¿Qué diferencia tiene con los horóscopos genéricos?',\n        acceptedAnswer: {\n          '@type': 'Answer',\n          text: 'Nuestros análisis son 100% personalizados: usan tu fecha, hora y lugar de nacimiento exactos. No son predicciones genéricas sino un mapa único de tu energía y propósito.',\n        },\n      },\n    ],\n  };\n}\n");
w("app/api/checkout/route.ts", "/**\n * app/api/checkout/route.ts\n * Checkout con Mercado Pago — reemplaza completamente Paddle.\n * Crea usuario, birth_data y transacción en Supabase, luego genera la URL de pago de MP.\n */\n\nimport { NextRequest, NextResponse } from 'next/server';\nimport { createClient } from '@supabase/supabase-js';\nimport { CheckoutRequestSchema, validateServerEnv } from '@/lib/validations/schemas';\nimport { MercadoPagoConfig, Preference } from 'mercadopago';\n\n// ─── Precios reales por producto ──────────────────────────────────────────────\nconst PRODUCT_PRICES: Record<string, { amount: number; title: string }> = {\n  'lectura-esencial': { amount: 10.5, title: 'Lectura Esencial — Astral Evolution' },\n  'consulta-evolutiva': { amount: 26.6, title: 'Consulta Evolutiva — Astral Evolution' },\n  'especial-parejas': { amount: 38.5, title: 'Especial Parejas — Astral Evolution' },\n};\n\n// ─── IDs de productos en Supabase (hardcoded como fallback seguro) ────────────\nconst PRODUCT_IDS: Record<string, string> = {\n  'lectura-esencial': 'e53d85c4-3599-4a82-80d8-5d313fc3c916',\n  'consulta-evolutiva': 'e1c9e6a0-2e6a-41b4-a741-c413b6c955f8',\n  'especial-parejas': '930bfe28-0c0f-433e-84bd-3cc57827aafa',\n};\n\nexport async function POST(request: NextRequest) {\n  // ─── 1. Validar entorno ───────────────────────────────────────────────────\n  try {\n    validateServerEnv();\n  } catch (envError) {\n    console.error('[Checkout] Error de configuración:', envError);\n    return NextResponse.json(\n      { error: 'Error de configuración del servidor. Contacta al administrador.' },\n      { status: 500 }\n    );\n  }\n\n  // ─── 2. Parsear y validar input con Zod ──────────────────────────────────\n  let body: unknown;\n  try {\n    body = await request.json();\n  } catch {\n    return NextResponse.json({ error: 'JSON inválido en el cuerpo de la petición.' }, { status: 400 });\n  }\n\n  const parsed = CheckoutRequestSchema.safeParse(body);\n  if (!parsed.success) {\n    const firstError = parsed.error.errors[0];\n    return NextResponse.json(\n      { error: firstError.message, field: firstError.path.join('.') },\n      { status: 422 }\n    );\n  }\n\n  const { productSlug, birthData, partnerBirthData, countryCode } = parsed.data;\n\n  // ─── 3. Verificar que el producto requiere partner data si aplica ──────────\n  if (productSlug === 'especial-parejas' && !partnerBirthData) {\n    return NextResponse.json(\n      { error: 'Se requieren los datos de nacimiento de la pareja para este producto.' },\n      { status: 422 }\n    );\n  }\n\n  const productPrice = PRODUCT_PRICES[productSlug];\n  if (!productPrice) {\n    return NextResponse.json({ error: 'Producto no encontrado.' }, { status: 404 });\n  }\n\n  // ─── 4. Inicializar clientes ─────────────────────────────────────────────\n  const supabase = createClient(\n    process.env.NEXT_PUBLIC_SUPABASE_URL!,\n    process.env.SUPABASE_SERVICE_ROLE_KEY!,\n    { auth: { persistSession: false } }\n  );\n\n  const mp = new MercadoPagoConfig({\n    accessToken: process.env.MERCADOPAGO_ACCESS_TOKEN!,\n  });\n  const preference = new Preference(mp);\n\n  try {\n    // ─── 5. Upsert de usuario ─────────────────────────────────────────────\n    const { data: user, error: userError } = await supabase\n      .from('users')\n      .upsert(\n        {\n          email: birthData.email,\n          name: birthData.name,\n          language: birthData.language ?? 'es',\n          country_code: countryCode,\n        },\n        { onConflict: 'email' }\n      )\n      .select('id')\n      .single();\n\n    if (userError || !user) {\n      console.error('[Checkout] Error upsert usuario:', userError);\n      return NextResponse.json(\n        { error: 'Error al registrar el usuario. Intenta nuevamente.' },\n        { status: 500 }\n      );\n    }\n\n    // ─── 6. Insertar birth_data principal ────────────────────────────────\n    const { data: birthRecord, error: birthError } = await supabase\n      .from('birth_data')\n      .insert({\n        user_id: user.id,\n        name: birthData.name,\n        birth_date: birthData.birthDate,\n        birth_time: birthData.birthTime,\n        birth_city: birthData.birthCity,\n        birth_country: birthData.birthCountry,\n        personal_context: birthData.personalContext ?? null,\n      })\n      .select('id')\n      .single();\n\n    if (birthError || !birthRecord) {\n      console.error('[Checkout] Error insertar birth_data:', birthError);\n      return NextResponse.json(\n        { error: 'Error al guardar los datos de nacimiento.' },\n        { status: 500 }\n      );\n    }\n\n    // ─── 7. Insertar birth_data de la pareja (si aplica) ─────────────────\n    let partnerBirthId: string | null = null;\n    if (partnerBirthData) {\n      const { data: partnerRecord, error: partnerError } = await supabase\n        .from('birth_data')\n        .insert({\n          user_id: user.id,\n          name: partnerBirthData.name,\n          birth_date: partnerBirthData.birthDate,\n          birth_time: partnerBirthData.birthTime,\n          birth_city: partnerBirthData.birthCity,\n          birth_country: partnerBirthData.birthCountry,\n          personal_context: partnerBirthData.personalContext ?? null,\n        })\n        .select('id')\n        .single();\n\n      if (partnerError) {\n        console.error('[Checkout] Error insertar partner birth_data:', partnerError);\n        // No fatal — continuar sin partner\n      } else {\n        partnerBirthId = partnerRecord?.id ?? null;\n      }\n    }\n\n    // ─── 8. Crear transacción pendiente en Supabase ───────────────────────\n    const { data: transaction, error: txError } = await supabase\n      .from('transactions')\n      .insert({\n        user_id: user.id,\n        product_id: PRODUCT_IDS[productSlug],\n        birth_data_id: birthRecord.id,\n        partner_birth_data_id: partnerBirthId,\n        amount: productPrice.amount,\n        currency: 'USD',\n        country_code: countryCode,\n        status: 'pending',\n      })\n      .select('id')\n      .single();\n\n    if (txError || !transaction) {\n      console.error('[Checkout] Error crear transacción:', txError);\n      return NextResponse.json(\n        { error: 'Error al inicializar el pago. Intenta nuevamente.' },\n        { status: 500 }\n      );\n    }\n\n    // ─── 9. Crear preferencia de Mercado Pago ────────────────────────────\n    const appUrl = process.env.NEXT_PUBLIC_APP_URL ?? 'https://astralevolution.com';\n\n    const mpPreference = await preference.create({\n      body: {\n        items: [\n          {\n            id: productSlug,\n            title: productPrice.title,\n            quantity: 1,\n            unit_price: productPrice.amount,\n            currency_id: 'USD',\n          },\n        ],\n        payer: {\n          name: birthData.name,\n          email: birthData.email,\n        },\n        external_reference: transaction.id,\n        back_urls: {\n          success: `${appUrl}/gracias?transactionId=${transaction.id}&status=approved`,\n          failure: `${appUrl}/pago-fallido?transactionId=${transaction.id}`,\n          pending: `${appUrl}/gracias?transactionId=${transaction.id}&status=pending`,\n        },\n        auto_return: 'approved',\n        notification_url: `${appUrl}/api/webhooks/mercadopago`,\n        statement_descriptor: 'ASTRAL EVOLUTION',\n        expires: true,\n        expiration_date_to: new Date(Date.now() + 2 * 60 * 60 * 1000).toISOString(), // 2 horas\n      },\n    });\n\n    if (!mpPreference.init_point) {\n      console.error('[Checkout] MP no retornó init_point:', mpPreference);\n      return NextResponse.json(\n        { error: 'Error al crear el enlace de pago. Intenta nuevamente.' },\n        { status: 500 }\n      );\n    }\n\n    return NextResponse.json({\n      checkoutUrl: mpPreference.init_point,\n      transactionId: transaction.id,\n    });\n  } catch (error) {\n    console.error('[Checkout] Error inesperado:', error);\n    return NextResponse.json(\n      {\n        error: 'Error interno del servidor.',\n        details: error instanceof Error ? error.message : 'Unknown error',\n      },\n      { status: 500 }\n    );\n  }\n}\n");
w("app/api/webhooks/mercadopago/route.ts", "/**\n * app/api/webhooks/mercadopago/route.ts\n * Webhook de Mercado Pago — verifica firma HMAC, actualiza transacción,\n * dispara generación de reporte y envía notificación WhatsApp.\n */\n\nimport { NextRequest, NextResponse } from 'next/server';\nimport { createClient } from '@supabase/supabase-js';\nimport crypto from 'crypto';\nimport { MercadoPagoWebhookSchema } from '@/lib/validations/schemas';\n\n// ─── Verificación de firma HMAC-SHA256 ────────────────────────────────────────\nfunction verifyMPSignature(request: NextRequest, rawBody: string): boolean {\n  const secret = process.env.MERCADOPAGO_WEBHOOK_SECRET?.trim();\n  if (!secret) {\n    console.warn('[Webhook MP] MERCADOPAGO_WEBHOOK_SECRET no configurado — saltando verificación');\n    return true; // Permitir en desarrollo si no hay secret\n  }\n\n  // MP envía x-signature: ts=<timestamp>,v1=<hash>\n  const xSignature = request.headers.get('x-signature');\n  const xRequestId = request.headers.get('x-request-id');\n  const dataId = new URL(request.url).searchParams.get('data.id');\n\n  if (!xSignature) {\n    console.error('[Webhook MP] Falta header x-signature');\n    return false;\n  }\n\n  const parts = Object.fromEntries(\n    xSignature.split(',').map((part) => part.split('=') as [string, string])\n  );\n  const ts = parts['ts'];\n  const v1 = parts['v1'];\n\n  if (!ts || !v1) {\n    console.error('[Webhook MP] Formato de firma inválido');\n    return false;\n  }\n\n  // Construir el mensaje según la documentación de MP\n  const manifest = [\n    dataId ? `id:${dataId}` : null,\n    xRequestId ? `request-id:${xRequestId}` : null,\n    `ts:${ts}`,\n  ]\n    .filter(Boolean)\n    .join(';');\n\n  const expectedHash = crypto\n    .createHmac('sha256', secret)\n    .update(manifest)\n    .digest('hex');\n\n  // Comparación en tiempo constante para evitar timing attacks\n  const isValid = crypto.timingSafeEqual(\n    Buffer.from(v1, 'hex'),\n    Buffer.from(expectedHash, 'hex')\n  );\n\n  return isValid;\n}\n\n// ─── Notificación WhatsApp via Twilio ─────────────────────────────────────────\nasync function sendWhatsAppNotification(\n  productName: string,\n  amount: number,\n  customerName: string,\n  customerEmail: string\n): Promise<void> {\n  const accountSid = process.env.TWILIO_ACCOUNT_SID?.trim();\n  const authToken = process.env.TWILIO_AUTH_TOKEN?.trim();\n  const fromNumber = process.env.TWILIO_WHATSAPP_FROM?.trim() ?? 'whatsapp:+14155238886';\n  const toNumber = process.env.WHATSAPP_NOTIFY_TO?.trim();\n\n  if (!accountSid || !authToken || !toNumber) {\n    console.warn('[WhatsApp] Credenciales no configuradas — saltando notificación');\n    return;\n  }\n\n  const message =\n    `🌟 *Nueva venta en Astral Evolution*\\n\\n` +\n    `📦 Producto: ${productName}\\n` +\n    `💰 Monto: $${amount.toFixed(2)} USD\\n` +\n    `👤 Cliente: ${customerName}\\n` +\n    `📧 Email: ${customerEmail}\\n` +\n    `⏰ Hora: ${new Date().toLocaleString('es-AR', { timeZone: 'America/Montevideo' })}`;\n\n  const url = `https://api.twilio.com/2010-04-01/Accounts/${accountSid}/Messages.json`;\n  const credentials = Buffer.from(`${accountSid}:${authToken}`).toString('base64');\n\n  const params = new URLSearchParams({\n    From: fromNumber,\n    To: `whatsapp:${toNumber}`,\n    Body: message,\n  });\n\n  try {\n    const res = await fetch(url, {\n      method: 'POST',\n      headers: {\n        Authorization: `Basic ${credentials}`,\n        'Content-Type': 'application/x-www-form-urlencoded',\n      },\n      body: params.toString(),\n    });\n\n    if (!res.ok) {\n      const err = await res.text();\n      console.error('[WhatsApp] Error Twilio:', err);\n    } else {\n      console.log('[WhatsApp] Notificación enviada OK');\n    }\n  } catch (err) {\n    console.error('[WhatsApp] Error de red:', err);\n  }\n}\n\n// ─── Handler principal ────────────────────────────────────────────────────────\nexport async function POST(request: NextRequest) {\n  // 1. Leer body como texto para verificar firma\n  const rawBody = await request.text();\n\n  // 2. Verificar firma de MP\n  if (!verifyMPSignature(request, rawBody)) {\n    console.error('[Webhook MP] Firma inválida — rechazando');\n    return NextResponse.json({ error: 'Firma inválida' }, { status: 401 });\n  }\n\n  // 3. Parsear y validar body\n  let webhookData: unknown;\n  try {\n    webhookData = JSON.parse(rawBody);\n  } catch {\n    return NextResponse.json({ error: 'JSON inválido' }, { status: 400 });\n  }\n\n  const parsed = MercadoPagoWebhookSchema.safeParse(webhookData);\n  if (!parsed.success) {\n    console.error('[Webhook MP] Schema inválido:', parsed.error.errors);\n    return NextResponse.json({ received: true }); // 200 para que MP no reintente\n  }\n\n  const { type, data } = parsed.data;\n\n  // 4. Solo procesar pagos aprobados\n  if (type !== 'payment' || !data?.id) {\n    return NextResponse.json({ received: true });\n  }\n\n  const mpPaymentId = data.id;\n  console.log(`[Webhook MP] Procesando pago ID: ${mpPaymentId}`);\n\n  // 5. Consultar estado del pago en MP API\n  const mpToken = process.env.MERCADOPAGO_ACCESS_TOKEN?.trim();\n  if (!mpToken) {\n    return NextResponse.json({ error: 'Token de MP no configurado' }, { status: 500 });\n  }\n\n  let paymentDetails: {\n    status: string;\n    external_reference: string;\n    transaction_amount: number;\n    payer?: { email?: string; first_name?: string; last_name?: string };\n  };\n\n  try {\n    const mpRes = await fetch(`https://api.mercadopago.com/v1/payments/${mpPaymentId}`, {\n      headers: { Authorization: `Bearer ${mpToken}` },\n    });\n\n    if (!mpRes.ok) {\n      console.error('[Webhook MP] Error consultando pago:', mpRes.status);\n      return NextResponse.json({ error: 'Error consultando pago' }, { status: 500 });\n    }\n\n    paymentDetails = await mpRes.json();\n  } catch (err) {\n    console.error('[Webhook MP] Error de red consultando pago:', err);\n    return NextResponse.json({ error: 'Error de red' }, { status: 500 });\n  }\n\n  if (paymentDetails.status !== 'approved') {\n    console.log(`[Webhook MP] Pago no aprobado (${paymentDetails.status}), ignorando`);\n    return NextResponse.json({ received: true });\n  }\n\n  const transactionId = paymentDetails.external_reference;\n  if (!transactionId) {\n    console.error('[Webhook MP] No hay external_reference en el pago');\n    return NextResponse.json({ received: true });\n  }\n\n  // 6. Actualizar transacción en Supabase\n  const supabase = createClient(\n    process.env.NEXT_PUBLIC_SUPABASE_URL!,\n    process.env.SUPABASE_SERVICE_ROLE_KEY!,\n    { auth: { persistSession: false } }\n  );\n\n  const { data: updatedTx, error: updateError } = await supabase\n    .from('transactions')\n    .update({\n      status: 'completed',\n      completed_at: new Date().toISOString(),\n      mp_payment_id: mpPaymentId,\n    })\n    .eq('id', transactionId)\n    .eq('status', 'pending') // Idempotencia: solo si estaba pendiente\n    .select('*, products(name_es, slug, base_price_usd), users(name, email)')\n    .single();\n\n  if (updateError) {\n    console.error('[Webhook MP] Error actualizando transacción:', updateError);\n    // No retornar error 500 — MP reintentaría\n    return NextResponse.json({ received: true });\n  }\n\n  if (!updatedTx) {\n    console.log('[Webhook MP] Transacción no encontrada o ya procesada (idempotente)');\n    return NextResponse.json({ received: true });\n  }\n\n  console.log(`[Webhook MP] Transacción ${transactionId} completada ✅`);\n\n  // 7. Crear registro de reporte pendiente\n  const { error: reportError } = await supabase.from('reports').insert({\n    transaction_id: transactionId,\n    status: 'pending',\n  });\n\n  if (reportError) {\n    console.error('[Webhook MP] Error creando registro de reporte:', reportError);\n  }\n\n  // 8. Disparar generación de reporte en background (fire-and-forget)\n  const appUrl = process.env.NEXT_PUBLIC_APP_URL ?? 'https://astralevolution.com';\n  fetch(`${appUrl}/api/generate-report`, {\n    method: 'POST',\n    headers: { 'Content-Type': 'application/json' },\n    body: JSON.stringify({ transactionId }),\n  }).catch((err) => console.error('[Webhook MP] Error disparando generación:', err));\n\n  // 9. Notificación WhatsApp\n  const productName = (updatedTx as any).products?.name_es ?? 'Producto desconocido';\n  const customerName = (updatedTx as any).users?.name ?? 'Cliente';\n  const customerEmail = (updatedTx as any).users?.email ?? '';\n  const amount = paymentDetails.transaction_amount;\n\n  sendWhatsAppNotification(productName, amount, customerName, customerEmail).catch((err) =>\n    console.error('[WhatsApp] Error enviando notificación:', err)\n  );\n\n  return NextResponse.json({ received: true, status: 'completed' });\n}\n");
w("app/api/generate-report/route.ts", "/**\n * app/api/generate-report/route.ts\n * Generación de reporte con Gemini 1.5 Flash + envío automático por email.\n * Versión completa: genera → sanitiza → guarda en DB → envía email.\n */\n\nimport { NextRequest, NextResponse } from 'next/server';\nimport { createClient } from '@supabase/supabase-js';\nimport { GenerateReportSchema, sanitizeAIOutput } from '@/lib/validations/schemas';\nimport { sendReportEmail } from '@/lib/email/send-report';\n\n// ─── Prompts por producto ─────────────────────────────────────────────────────\nfunction buildPrompt(\n  productSlug: string,\n  birthData: {\n    name: string;\n    birth_date: string;\n    birth_time: string;\n    birth_city: string;\n    birth_country: string;\n    personal_context?: string | null;\n  },\n  partnerData?: {\n    name: string;\n    birth_date: string;\n    birth_time: string;\n    birth_city: string;\n    birth_country: string;\n  } | null\n): string {\n  const mes = new Date().toLocaleString('es-ES', { month: 'long', year: 'numeric' });\n\n  const base = `\nNombre: ${birthData.name}\nFecha de nacimiento: ${birthData.birth_date}\nHora de nacimiento: ${birthData.birth_time}\nCiudad: ${birthData.birth_city}, ${birthData.birth_country}\n${birthData.personal_context ? `Contexto personal: ${birthData.personal_context}` : ''}\n  `.trim();\n\n  if (productSlug === 'lectura-esencial') {\n    return `Eres un astrólogo profesional experto en astrología evolutiva. Genera una Lectura Esencial personalizada para:\n\n${base}\n\nIncluye:\n**Sol, Luna y Ascendente** — Las tres luminarias principales y su expresión en la personalidad.\n**Tránsitos de ${mes}** — Qué energías están activas y cómo aprovecharlas.\n**3 Recomendaciones concretas** — Acciones específicas alineadas con la energía actual.\n\nExtensión: 4-6 párrafos bien desarrollados. Usa **negritas** para los títulos de sección. No uses HTML ni markdown complejo. Tono: profundo, inspirador y accesible.`;\n  }\n\n  if (productSlug === 'consulta-evolutiva') {\n    return `Eres un astrólogo profesional experto en astrología evolutiva y karmica. Genera una Consulta Evolutiva completa para:\n\n${base}\n\nIncluye:\n**Carta Natal** — Sol, Luna, Ascendente y planetas personales (Mercurio, Venus, Marte, Júpiter, Saturno).\n**Las Casas Clave** — Las 3-4 casas más activadas y su mensaje evolutivo.\n**Aspectos Planetarios Principales** — Las configuraciones más significativas.\n**Nodos Lunares** — Nodo Norte (misión del alma) y Nodo Sur (karma a soltar).\n**Quirón** — La herida primordial y el camino de sanación.\n**Tránsitos Importantes del Año** — Saturno, Júpiter y planetas lentos.\n**Revolución Solar** — El foco del año en curso.\n**Plan de Crecimiento** — 5 áreas de trabajo y recomendaciones específicas.\n\nExtensión: 12-15 párrafos profundos. Usa **negritas** para los títulos. Tono: transformador y evolutivo.`;\n  }\n\n  if (productSlug === 'especial-parejas' && partnerData) {\n    return `Eres un astrólogo especializado en sinastría y astrología relacional. Genera un Especial Parejas para:\n\n**PERSONA 1:**\n${base}\n\n**PERSONA 2:**\nNombre: ${partnerData.name}\nFecha: ${partnerData.birth_date}\nHora: ${partnerData.birth_time}\nCiudad: ${partnerData.birth_city}, ${partnerData.birth_country}\n\nIncluye:\n**Compatibilidad Esencial** — Sol, Luna y Ascendente de ambos y su dinámica.\n**Sinastría** — Los 5-7 aspectos interplanetarios más significativos.\n**Casas Activadas** — Qué activa cada uno en la carta del otro.\n**Fortalezas de la Pareja** — Los 3 mayores dones compartidos.\n**Desafíos y Crecimiento** — 3 áreas de fricción y cómo trabajarlas conscientemente.\n**Propósito Conjunto** — La misión evolutiva de esta relación.\n**5 Prácticas Recomendadas** — Acciones concretas para fortalecer el vínculo.\n\nExtensión: 14-18 párrafos. Usa **negritas** para títulos. Tono: revelador, compasivo y orientado al crecimiento.`;\n  }\n\n  return `Genera un análisis astrológico personalizado para ${birthData.name}, nacido/a el ${birthData.birth_date} a las ${birthData.birth_time} en ${birthData.birth_city}, ${birthData.birth_country}. Sé profundo y evolutivo.`;\n}\n\n// ─── Llamada a Gemini con limpieza de key ─────────────────────────────────────\nasync function callGemini(prompt: string): Promise<string> {\n  // Limpia saltos de línea invisibles — bug conocido con echo en Vercel CLI\n  const apiKey = process.env.GEMINI_API_KEY?.replace(/[\\r\\n\\s]/g, '');\n  if (!apiKey) throw new Error('GEMINI_API_KEY no configurada');\n\n  const url = `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=${apiKey}`;\n\n  const res = await fetch(url, {\n    method: 'POST',\n    headers: { 'Content-Type': 'application/json' },\n    body: JSON.stringify({\n      contents: [{ role: 'user', parts: [{ text: prompt }] }],\n      generationConfig: {\n        temperature: 0.8,\n        topK: 40,\n        topP: 0.95,\n        maxOutputTokens: 4096,\n      },\n      safetySettings: [\n        { category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_MEDIUM_AND_ABOVE' },\n        { category: 'HARM_CATEGORY_HATE_SPEECH', threshold: 'BLOCK_MEDIUM_AND_ABOVE' },\n        { category: 'HARM_CATEGORY_SEXUALLY_EXPLICIT', threshold: 'BLOCK_MEDIUM_AND_ABOVE' },\n        { category: 'HARM_CATEGORY_DANGEROUS_CONTENT', threshold: 'BLOCK_MEDIUM_AND_ABOVE' },\n      ],\n    }),\n  });\n\n  if (!res.ok) {\n    const err = await res.text();\n    throw new Error(`Gemini ${res.status}: ${err}`);\n  }\n\n  const data = await res.json();\n  const text = data?.candidates?.[0]?.content?.parts?.[0]?.text;\n  if (!text) throw new Error('Gemini no retornó texto');\n  return text;\n}\n\n// ─── Handler ──────────────────────────────────────────────────────────────────\nexport async function POST(request: NextRequest) {\n  let body: unknown;\n  try {\n    body = await request.json();\n  } catch {\n    return NextResponse.json({ error: 'JSON inválido' }, { status: 400 });\n  }\n\n  const parsed = GenerateReportSchema.safeParse(body);\n  if (!parsed.success) {\n    return NextResponse.json({ error: parsed.error.errors[0].message }, { status: 422 });\n  }\n\n  const { transactionId } = parsed.data;\n\n  const supabase = createClient(\n    process.env.NEXT_PUBLIC_SUPABASE_URL!,\n    process.env.SUPABASE_SERVICE_ROLE_KEY!,\n    { auth: { persistSession: false } }\n  );\n\n  // Marcar como \"generating\"\n  await supabase\n    .from('reports')\n    .update({ status: 'generating' })\n    .eq('transaction_id', transactionId);\n\n  try {\n    // Obtener transacción con todos los datos necesarios\n    const { data: tx, error: txError } = await supabase\n      .from('transactions')\n      .select(`\n        *,\n        products(slug, name_es),\n        birth_data!transactions_birth_data_id_fkey(\n          name, birth_date, birth_time, birth_city, birth_country, personal_context\n        ),\n        partner_birth_data:birth_data!transactions_partner_birth_data_id_fkey(\n          name, birth_date, birth_time, birth_city, birth_country\n        ),\n        users(name, email)\n      `)\n      .eq('id', transactionId)\n      .eq('status', 'completed')\n      .single();\n\n    if (txError || !tx) {\n      throw new Error(`Transacción no encontrada o no completada`);\n    }\n\n    const productSlug = (tx as any).products?.slug;\n    const productName = (tx as any).products?.name_es ?? 'Lectura Astrológica';\n    const birthData = (tx as any).birth_data;\n    const partnerData = (tx as any).partner_birth_data ?? null;\n    const userEmail = (tx as any).users?.email;\n    const userName = (tx as any).users?.name ?? birthData?.name;\n\n    if (!birthData) throw new Error('Datos de nacimiento no encontrados');\n\n    // Generar reporte con Gemini\n    const prompt = buildPrompt(productSlug, birthData, partnerData);\n    const rawText = await callGemini(prompt);\n\n    // Sanitizar ANTES de guardar\n    const sanitizedText = sanitizeAIOutput(rawText);\n\n    // Guardar en DB\n    await supabase\n      .from('reports')\n      .update({\n        status: 'completed',\n        ai_response: sanitizedText,\n        generated_at: new Date().toISOString(),\n      })\n      .eq('transaction_id', transactionId);\n\n    console.log(`[GenerateReport] ✅ Reporte generado para ${transactionId}`);\n\n    // Enviar email si tenemos la dirección\n    if (userEmail) {\n      const emailResult = await sendReportEmail({\n        toEmail: userEmail,\n        toName: userName,\n        productName,\n        reportContent: sanitizedText,\n        transactionId,\n      });\n\n      if (emailResult.success) {\n        // Marcar como enviado\n        await supabase\n          .from('reports')\n          .update({ sent_at: new Date().toISOString() })\n          .eq('transaction_id', transactionId);\n        console.log(`[GenerateReport] ✅ Email enviado a ${userEmail}`);\n      } else {\n        console.error(`[GenerateReport] ⚠️ Email falló:`, emailResult.error);\n      }\n    }\n\n    return NextResponse.json({ success: true, transactionId });\n\n  } catch (error) {\n    const msg = error instanceof Error ? error.message : 'Error desconocido';\n    console.error('[GenerateReport] ❌', msg);\n\n    await supabase\n      .from('reports')\n      .update({ status: 'failed', error_message: msg })\n      .eq('transaction_id', transactionId);\n\n    return NextResponse.json({ error: msg }, { status: 500 });\n  }\n}\n");
w("app/api/report-status/route.ts", "/**\n * app/api/report-status/route.ts\n * Consulta el estado del reporte para la página /gracias\n */\n\nimport { NextRequest, NextResponse } from 'next/server';\nimport { createClient } from '@supabase/supabase-js';\nimport { z } from 'zod';\n\nconst QuerySchema = z.object({\n  transactionId: z.string().uuid('ID inválido'),\n});\n\nexport async function GET(request: NextRequest) {\n  const { searchParams } = new URL(request.url);\n  const parsed = QuerySchema.safeParse({ transactionId: searchParams.get('transactionId') });\n\n  if (!parsed.success) {\n    return NextResponse.json({ error: 'ID de transacción inválido' }, { status: 400 });\n  }\n\n  const { transactionId } = parsed.data;\n\n  const supabase = createClient(\n    process.env.NEXT_PUBLIC_SUPABASE_URL!,\n    process.env.SUPABASE_SERVICE_ROLE_KEY!,\n    { auth: { persistSession: false } }\n  );\n\n  const { data, error } = await supabase\n    .from('reports')\n    .select('status, generated_at')\n    .eq('transaction_id', transactionId)\n    .maybeSingle();\n\n  if (error) {\n    return NextResponse.json({ error: 'Error consultando reporte' }, { status: 500 });\n  }\n\n  if (!data) {\n    return NextResponse.json({ status: 'not_found' });\n  }\n\n  return NextResponse.json({ status: data.status, generatedAt: data.generated_at });\n}\n");
w("app/api/cron/birthday/route.ts", "/**\n * app/api/cron/birthday/route.ts — VERSIÓN FINAL con deduplicación\n * Cron job diario que detecta clientes que cumplen años HOY,\n * genera su mini Revolución Solar con Gemini y les envía el email.\n *\n * Configurar en vercel.json:\n * { \"crons\": [{ \"path\": \"/api/cron/birthday\", \"schedule\": \"0 10 * * *\" }] }\n *\n * Se ejecuta todos los días a las 10:00 AM UTC (7 AM Argentina / Uruguay).\n * Protegido con CRON_SECRET para que solo Vercel pueda invocarlo.\n */\n\nimport { NextRequest, NextResponse } from 'next/server';\nimport { createClient } from '@supabase/supabase-js';\nimport { sanitizeAIOutput } from '@/lib/validations/schemas';\nimport { sendBirthdayEmail } from '@/lib/email/send-birthday';\n\n// ─── Prompt para mini Revolución Solar ───────────────────────────────────────\nfunction buildBirthdayPrompt(\n  name: string,\n  birthDate: string,\n  birthTime: string,\n  birthCity: string,\n  birthCountry: string\n): string {\n  const currentYear = new Date().getFullYear();\n\n  return `Eres un astrólogo cálido y profundo. Hoy es el cumpleaños de ${name}.\n\nDatos de nacimiento:\n- Fecha: ${birthDate}\n- Hora: ${birthTime}\n- Lugar: ${birthCity}, ${birthCountry}\n\nGenera un mini análisis de su **Revolución Solar ${currentYear}-${currentYear + 1}**. \nDebe incluir exactamente 3 puntos concretos y reveladores sobre su año:\n\n1. **El gran tema del año** — el área principal de vida que estará activada (trabajo, amor, familia, identidad, espiritualidad, etc.) y por qué.\n\n2. **Una oportunidad que no debe perderse** — algo específico que el cielo está abriendo para esta persona este año. Ser concreto y esperanzador.\n\n3. **Un desafío que la hará crecer** — algo que vendrá a transformarlos. No alarmante — enfocado en el crecimiento que trae.\n\nEstilo: íntimo, como si le hablaras directamente. Usar \"tu\" y \"vos\" (habla rioplatense). \nQue se sienta especial, no genérico.\nLongitud: 3 párrafos breves pero sustanciosos (8-10 líneas en total).\nCerrar con una frase poética de 1 línea sobre el nuevo ciclo solar.\nUsar **negritas** para los títulos de cada punto. No uses HTML.`;\n}\n\n// ─── Llamada a Gemini ─────────────────────────────────────────────────────────\nasync function callGemini(prompt: string): Promise<string> {\n  const apiKey = process.env.GEMINI_API_KEY?.replace(/[\\r\\n\\s]/g, '');\n  if (!apiKey) throw new Error('GEMINI_API_KEY no configurada');\n\n  const url = `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=${apiKey}`;\n\n  const res = await fetch(url, {\n    method: 'POST',\n    headers: { 'Content-Type': 'application/json' },\n    body: JSON.stringify({\n      contents: [{ role: 'user', parts: [{ text: prompt }] }],\n      generationConfig: { temperature: 0.85, maxOutputTokens: 600 },\n    }),\n  });\n\n  if (!res.ok) throw new Error(`Gemini ${res.status}`);\n\n  const data = await res.json();\n  const text = data?.candidates?.[0]?.content?.parts?.[0]?.text;\n  if (!text) throw new Error('Gemini no retornó texto');\n  return text;\n}\n\n// ─── Handler del cron ─────────────────────────────────────────────────────────\nexport async function GET(request: NextRequest) {\n  // Verificar que la llamada viene de Vercel Cron (o de nosotros en dev)\n  const authHeader = request.headers.get('authorization');\n  const cronSecret = process.env.CRON_SECRET?.trim();\n\n  if (cronSecret && authHeader !== `Bearer ${cronSecret}`) {\n    return NextResponse.json({ error: 'No autorizado' }, { status: 401 });\n  }\n\n  const supabase = createClient(\n    process.env.NEXT_PUBLIC_SUPABASE_URL!,\n    process.env.SUPABASE_SERVICE_ROLE_KEY!,\n    { auth: { persistSession: false } }\n  );\n\n  // Obtener fecha de hoy en formato MM-DD (año no importa)\n  const today = new Date();\n  const todayMMDD = `${String(today.getMonth() + 1).padStart(2, '0')}-${String(today.getDate()).padStart(2, '0')}`;\n\n  console.log(`[Birthday Cron] Buscando cumpleaños del ${todayMMDD}`);\n\n  // Buscar clientes que cumplen años hoy\n  // birth_date es DATE en Supabase → comparamos mes-día con TO_CHAR\n  const { data: birthdays, error } = await supabase\n    .from('birth_data')\n    .select(`\n      id,\n      name,\n      birth_date,\n      birth_time,\n      birth_city,\n      birth_country,\n      user_id,\n      users!inner(id, email, name)\n    `)\n    .filter('birth_date', 'not.is', null)\n    // Filtrar por mes-día usando RPC personalizado o haciendo el filtro en JS\n    // (Supabase no tiene TO_CHAR directo en el SDK, lo haremos en JS)\n\n  if (error) {\n    console.error('[Birthday Cron] Error consultando DB:', error);\n    return NextResponse.json({ error: error.message }, { status: 500 });\n  }\n\n  // Filtrar en JavaScript los que cumplen hoy\n  const todayBirthdays = (birthdays ?? []).filter((bd: any) => {\n    if (!bd.birth_date) return false;\n    const bdMMDD = bd.birth_date.slice(5); // \"YYYY-MM-DD\" → \"MM-DD\"\n    return bdMMDD === todayMMDD;\n  });\n\n  console.log(`[Birthday Cron] Encontrados ${todayBirthdays.length} cumpleaños hoy`);\n\n  const results = { sent: 0, failed: 0, errors: [] as string[] };\n\n  for (const bd of todayBirthdays) {\n    const user = (bd as any).users;\n    if (!user?.email) continue;\n\n    try {\n      // Generar mini análisis con Gemini\n      const prompt = buildBirthdayPrompt(\n        bd.name,\n        bd.birth_date,\n        bd.birth_time ?? '12:00',\n        bd.birth_city,\n        bd.birth_country\n      );\n\n      const rawAnalysis = await callGemini(prompt);\n      const cleanAnalysis = sanitizeAIOutput(rawAnalysis);\n\n      // Enviar email\n      const emailResult = await sendBirthdayEmail({\n        toEmail: user.email,\n        toName: bd.name,\n        birthDate: bd.birth_date,\n        birthCity: bd.birth_city,\n        birthCountry: bd.birth_country,\n        miniAnalysis: cleanAnalysis,\n        userId: bd.user_id,\n      });\n\n      if (emailResult.success) {\n        results.sent++;\n        console.log(`[Birthday Cron] ✅ Email enviado a ${user.email}`);\n      } else {\n        results.failed++;\n        results.errors.push(`${user.email}: ${emailResult.error}`);\n      }\n\n      // Pequeña pausa entre emails para no saturar la API de Gemini\n      await new Promise((r) => setTimeout(r, 2000));\n\n    } catch (err) {\n      results.failed++;\n      const msg = err instanceof Error ? err.message : 'Error desconocido';\n      results.errors.push(`${user.email}: ${msg}`);\n      console.error(`[Birthday Cron] ❌ Error para ${user.email}:`, msg);\n    }\n  }\n\n  console.log(`[Birthday Cron] Completado — enviados: ${results.sent}, fallidos: ${results.failed}`);\n\n  return NextResponse.json({\n    date: todayMMDD,\n    found: todayBirthdays.length,\n    ...results,\n  });\n}\n");
w("app/gracias/page.tsx", "'use client';\n\nimport { useEffect, useState } from 'react';\nimport { useSearchParams } from 'next/navigation';\nimport { Sparkles, CheckCircle, Clock, Mail, RefreshCw } from 'lucide-react';\n\ntype ReportStatus = 'pending' | 'generating' | 'completed' | 'failed' | 'not_found' | 'loading';\n\nexport default function GraciasPage() {\n  const searchParams = useSearchParams();\n  const transactionId = searchParams.get('transactionId');\n  const status = searchParams.get('status');\n\n  const [reportStatus, setReportStatus] = useState<ReportStatus>('loading');\n  const [pollCount, setPollCount] = useState(0);\n\n  useEffect(() => {\n    if (!transactionId) return;\n\n    async function checkStatus() {\n      try {\n        const res = await fetch(`/api/report-status?transactionId=${transactionId}`);\n        if (!res.ok) {\n          setReportStatus('not_found');\n          return;\n        }\n        const data = await res.json();\n        setReportStatus(data.status ?? 'pending');\n      } catch {\n        setReportStatus('pending');\n      }\n    }\n\n    checkStatus();\n\n    // Polling cada 15 segundos, máximo 10 veces (2.5 min)\n    const interval = setInterval(() => {\n      setPollCount((c) => {\n        if (c >= 10) {\n          clearInterval(interval);\n          return c;\n        }\n        checkStatus();\n        return c + 1;\n      });\n    }, 15000);\n\n    return () => clearInterval(interval);\n  }, [transactionId]);\n\n  const isPending = status === 'pending';\n\n  return (\n    <main className=\"min-h-screen flex items-center justify-center py-20 px-4\">\n      {/* Fondo estrellas */}\n      <div className=\"fixed inset-0 overflow-hidden pointer-events-none\">\n        {[...Array(40)].map((_, i) => (\n          <div\n            key={i}\n            className=\"absolute rounded-full bg-white\"\n            style={{\n              width: Math.random() * 2 + 1 + 'px',\n              height: Math.random() * 2 + 1 + 'px',\n              top: Math.random() * 100 + '%',\n              left: Math.random() * 100 + '%',\n              opacity: Math.random() * 0.6 + 0.2,\n              animation: `twinkle ${Math.random() * 3 + 2}s ease-in-out infinite`,\n              animationDelay: Math.random() * 3 + 's',\n            }}\n          />\n        ))}\n      </div>\n\n      <style jsx global>{`\n        @keyframes twinkle {\n          0%, 100% { opacity: 0.2; transform: scale(1); }\n          50% { opacity: 0.8; transform: scale(1.3); }\n        }\n        @keyframes float {\n          0%, 100% { transform: translateY(0px); }\n          50% { transform: translateY(-10px); }\n        }\n        @keyframes pulse-glow {\n          0%, 100% { box-shadow: 0 0 20px rgba(139, 92, 246, 0.3); }\n          50% { box-shadow: 0 0 40px rgba(139, 92, 246, 0.6); }\n        }\n      `}</style>\n\n      <div className=\"relative z-10 max-w-2xl w-full text-center\">\n        {/* Icono principal */}\n        <div\n          className=\"inline-flex items-center justify-center w-24 h-24 rounded-full mb-8\"\n          style={{\n            background: 'linear-gradient(135deg, rgba(139, 92, 246, 0.3), rgba(59, 130, 246, 0.3))',\n            border: '1px solid rgba(139, 92, 246, 0.4)',\n            animation: 'float 3s ease-in-out infinite, pulse-glow 3s ease-in-out infinite',\n          }}\n        >\n          {isPending ? (\n            <Clock className=\"w-12 h-12 text-yellow-400\" />\n          ) : (\n            <CheckCircle className=\"w-12 h-12 text-green-400\" />\n          )}\n        </div>\n\n        {/* Título */}\n        <h1 className=\"text-4xl md:text-5xl font-bold mb-4 bg-gradient-to-r from-purple-400 via-blue-400 to-purple-300 bg-clip-text text-transparent\">\n          {isPending ? '¡Pago en Proceso!' : '¡Pago Exitoso!'}\n        </h1>\n\n        <p className=\"text-xl text-gray-300 mb-8\">\n          {isPending\n            ? 'Tu pago está siendo procesado. Recibirás tu lectura cuando se confirme.'\n            : 'Tu lectura astrológica está siendo preparada con amor y precisión.'}\n        </p>\n\n        {/* Estado del reporte */}\n        <div\n          className=\"rounded-2xl p-6 mb-8\"\n          style={{\n            background: 'rgba(255, 255, 255, 0.05)',\n            border: '1px solid rgba(255, 255, 255, 0.1)',\n            backdropFilter: 'blur(10px)',\n          }}\n        >\n          <div className=\"flex items-center gap-3 mb-4\">\n            <Sparkles className=\"w-5 h-5 text-purple-400 flex-shrink-0\" />\n            <h2 className=\"text-lg font-semibold text-white\">Estado de tu Reporte</h2>\n          </div>\n\n          {reportStatus === 'loading' && (\n            <div className=\"flex items-center gap-3 text-gray-400\">\n              <RefreshCw className=\"w-4 h-4 animate-spin\" />\n              <span>Verificando estado...</span>\n            </div>\n          )}\n\n          {(reportStatus === 'pending' || reportStatus === 'generating') && (\n            <div className=\"flex items-center gap-3\">\n              <div className=\"flex gap-1\">\n                {[0, 1, 2].map((i) => (\n                  <div\n                    key={i}\n                    className=\"w-2 h-2 rounded-full bg-purple-400\"\n                    style={{ animation: `pulse 1s ease-in-out infinite`, animationDelay: `${i * 0.2}s` }}\n                  />\n                ))}\n              </div>\n              <span className=\"text-purple-300\">\n                {reportStatus === 'generating'\n                  ? 'Gemini está generando tu lectura astrológica...'\n                  : 'Tu reporte está en cola de generación...'}\n              </span>\n            </div>\n          )}\n\n          {reportStatus === 'completed' && (\n            <div className=\"flex items-center gap-3 text-green-400\">\n              <CheckCircle className=\"w-5 h-5\" />\n              <span>¡Tu reporte fue generado exitosamente!</span>\n            </div>\n          )}\n\n          {reportStatus === 'failed' && (\n            <div className=\"text-red-400 text-sm\">\n              Hubo un problema generando tu reporte. Nuestro equipo lo resolverá pronto.\n            </div>\n          )}\n\n          {reportStatus === 'not_found' && (\n            <div className=\"text-yellow-400 text-sm\">\n              Procesando tu pedido... Esto puede tomar unos minutos.\n            </div>\n          )}\n        </div>\n\n        {/* Info de entrega */}\n        <div\n          className=\"rounded-2xl p-6 mb-8\"\n          style={{\n            background: 'rgba(255, 255, 255, 0.03)',\n            border: '1px solid rgba(255, 255, 255, 0.08)',\n          }}\n        >\n          <div className=\"flex items-center gap-3 mb-4\">\n            <Mail className=\"w-5 h-5 text-blue-400 flex-shrink-0\" />\n            <h2 className=\"text-lg font-semibold text-white\">¿Qué sigue?</h2>\n          </div>\n          <div className=\"space-y-3 text-sm text-gray-400 text-left\">\n            <div className=\"flex items-start gap-3\">\n              <div className=\"w-5 h-5 rounded-full bg-purple-500/20 border border-purple-500/40 flex items-center justify-center flex-shrink-0 mt-0.5 text-xs text-purple-300\">1</div>\n              <span>Tu lectura astrológica se genera automáticamente usando Inteligencia Artificial.</span>\n            </div>\n            <div className=\"flex items-start gap-3\">\n              <div className=\"w-5 h-5 rounded-full bg-purple-500/20 border border-purple-500/40 flex items-center justify-center flex-shrink-0 mt-0.5 text-xs text-purple-300\">2</div>\n              <span>Recibirás un email con tu reporte completo en formato PDF en los próximos 10-30 minutos.</span>\n            </div>\n            <div className=\"flex items-start gap-3\">\n              <div className=\"w-5 h-5 rounded-full bg-purple-500/20 border border-purple-500/40 flex items-center justify-center flex-shrink-0 mt-0.5 text-xs text-purple-300\">3</div>\n              <span>Si tienes dudas, escríbenos a <span className=\"text-purple-400\">contacto@astralevolution.com</span></span>\n            </div>\n          </div>\n        </div>\n\n        <button\n          onClick={() => (window.location.href = '/')}\n          className=\"px-8 py-3 rounded-full font-medium transition-all duration-300\"\n          style={{\n            background: 'linear-gradient(135deg, rgba(139, 92, 246, 0.4), rgba(59, 130, 246, 0.4))',\n            border: '1px solid rgba(139, 92, 246, 0.5)',\n            color: 'white',\n          }}\n        >\n          Volver al inicio ✨\n        </button>\n      </div>\n    </main>\n  );\n}\n");
w("app/pago-fallido/page.tsx", "'use client';\n\nimport { useSearchParams } from 'next/navigation';\nimport { XCircle, RefreshCw, MessageCircle } from 'lucide-react';\n\nexport default function PagoFallidoPage() {\n  const searchParams = useSearchParams();\n  const transactionId = searchParams.get('transactionId');\n\n  return (\n    <main className=\"min-h-screen flex items-center justify-center py-20 px-4\">\n      {/* Fondo estrellas */}\n      <div className=\"fixed inset-0 overflow-hidden pointer-events-none\">\n        {[...Array(30)].map((_, i) => (\n          <div\n            key={i}\n            className=\"absolute rounded-full bg-white\"\n            style={{\n              width: Math.random() * 2 + 1 + 'px',\n              height: Math.random() * 2 + 1 + 'px',\n              top: Math.random() * 100 + '%',\n              left: Math.random() * 100 + '%',\n              opacity: Math.random() * 0.4 + 0.1,\n            }}\n          />\n        ))}\n      </div>\n\n      <div className=\"relative z-10 max-w-lg w-full text-center\">\n        {/* Icono */}\n        <div\n          className=\"inline-flex items-center justify-center w-20 h-20 rounded-full mb-8\"\n          style={{\n            background: 'linear-gradient(135deg, rgba(239, 68, 68, 0.2), rgba(220, 38, 38, 0.1))',\n            border: '1px solid rgba(239, 68, 68, 0.3)',\n          }}\n        >\n          <XCircle className=\"w-10 h-10 text-red-400\" />\n        </div>\n\n        <h1 className=\"text-3xl md:text-4xl font-bold mb-4 text-white\">\n          El pago no se completó\n        </h1>\n\n        <p className=\"text-gray-400 text-lg mb-10\">\n          No se realizó ningún cobro. Podés intentarlo nuevamente cuando quieras.\n        </p>\n\n        {/* Opciones */}\n        <div className=\"space-y-4\">\n          <button\n            onClick={() => window.history.back()}\n            className=\"w-full flex items-center justify-center gap-3 px-6 py-4 rounded-2xl font-medium transition-all duration-300\"\n            style={{\n              background: 'linear-gradient(135deg, rgba(139, 92, 246, 0.4), rgba(59, 130, 246, 0.3))',\n              border: '1px solid rgba(139, 92, 246, 0.5)',\n              color: 'white',\n            }}\n          >\n            <RefreshCw className=\"w-5 h-5\" />\n            Intentar nuevamente\n          </button>\n\n          <a\n            href=\"/\"\n            className=\"w-full flex items-center justify-center gap-3 px-6 py-4 rounded-2xl font-medium transition-all duration-300\"\n            style={{\n              background: 'rgba(255,255,255,0.05)',\n              border: '1px solid rgba(255,255,255,0.1)',\n              color: '#9ca3af',\n            }}\n          >\n            Volver al inicio\n          </a>\n\n          <a\n            href=\"mailto:contacto@astralevolution.com\"\n            className=\"w-full flex items-center justify-center gap-3 px-6 py-3 rounded-2xl text-sm transition-all duration-300\"\n            style={{ color: '#6b7280' }}\n          >\n            <MessageCircle className=\"w-4 h-4\" />\n            ¿Necesitás ayuda? Contactanos\n          </a>\n        </div>\n\n        {transactionId && (\n          <p className=\"mt-8 text-xs text-gray-600\">\n            Referencia: {transactionId}\n          </p>\n        )}\n      </div>\n    </main>\n  );\n}\n");
w("middleware.ts", "import { NextRequest, NextResponse } from 'next/server';\n\n// ─── In-memory rate limit store (use Upstash Redis in production for multi-instance) ───\nconst rateLimitStore = new Map<string, { count: number; resetAt: number }>();\n\nfunction getRateLimitKey(ip: string, type: 'payment' | 'report' | 'general'): string {\n  return `${type}:${ip}`;\n}\n\nfunction checkRateLimit(\n  ip: string,\n  type: 'payment' | 'report' | 'general',\n  maxRequests: number,\n  windowMs: number\n): { allowed: boolean; remaining: number; resetAt: number } {\n  const key = getRateLimitKey(ip, type);\n  const now = Date.now();\n  const entry = rateLimitStore.get(key);\n\n  if (!entry || now > entry.resetAt) {\n    const resetAt = now + windowMs;\n    rateLimitStore.set(key, { count: 1, resetAt });\n    return { allowed: true, remaining: maxRequests - 1, resetAt };\n  }\n\n  if (entry.count >= maxRequests) {\n    return { allowed: false, remaining: 0, resetAt: entry.resetAt };\n  }\n\n  entry.count += 1;\n  return { allowed: true, remaining: maxRequests - entry.count, resetAt: entry.resetAt };\n}\n\n// ─── Clean expired entries every 5 minutes ───\nsetInterval(() => {\n  const now = Date.now();\n  for (const [key, value] of rateLimitStore.entries()) {\n    if (now > value.resetAt) rateLimitStore.delete(key);\n  }\n}, 5 * 60 * 1000);\n\nexport function middleware(request: NextRequest) {\n  const { pathname } = request.nextUrl;\n  const ip =\n    request.headers.get('x-forwarded-for')?.split(',')[0]?.trim() ||\n    request.headers.get('x-real-ip') ||\n    '127.0.0.1';\n\n  // ─── Rate Limiting per route type ───\n  if (pathname.startsWith('/api/checkout') || pathname.startsWith('/api/webhooks/mercadopago')) {\n    const limit = checkRateLimit(ip, 'payment', 5, 60 * 60 * 1000); // 5/hour\n    if (!limit.allowed) {\n      return new NextResponse(\n        JSON.stringify({ error: 'Demasiados intentos de pago. Intenta en 1 hora.' }),\n        {\n          status: 429,\n          headers: {\n            'Content-Type': 'application/json',\n            'Retry-After': String(Math.ceil((limit.resetAt - Date.now()) / 1000)),\n            'X-RateLimit-Limit': '5',\n            'X-RateLimit-Remaining': '0',\n          },\n        }\n      );\n    }\n  }\n\n  if (pathname.startsWith('/api/generate-report') || pathname.startsWith('/api/test-gemini')) {\n    const limit = checkRateLimit(ip, 'report', 10, 60 * 60 * 1000); // 10/hour\n    if (!limit.allowed) {\n      return new NextResponse(\n        JSON.stringify({ error: 'Límite de generación de reportes alcanzado. Intenta en 1 hora.' }),\n        {\n          status: 429,\n          headers: {\n            'Content-Type': 'application/json',\n            'Retry-After': String(Math.ceil((limit.resetAt - Date.now()) / 1000)),\n            'X-RateLimit-Limit': '10',\n            'X-RateLimit-Remaining': '0',\n          },\n        }\n      );\n    }\n  }\n\n  const response = NextResponse.next();\n\n  // ─── Security Headers ───\n  const cspDirectives = [\n    \"default-src 'self'\",\n    \"script-src 'self' 'unsafe-inline' 'unsafe-eval' https://sdk.mercadopago.com https://http2.mlstatic.com\",\n    \"style-src 'self' 'unsafe-inline' https://fonts.googleapis.com\",\n    \"font-src 'self' https://fonts.gstatic.com\",\n    \"img-src 'self' data: blob: https://http2.mlstatic.com https://secure.mlstatic.com\",\n    \"connect-src 'self' https://*.supabase.co https://generativelanguage.googleapis.com https://api.mercadopago.com\",\n    \"frame-src 'self' https://sdk.mercadopago.com https://www.mercadopago.com\",\n    \"frame-ancestors 'none'\",\n    \"form-action 'self'\",\n    \"base-uri 'self'\",\n    \"upgrade-insecure-requests\",\n  ].join('; ');\n\n  response.headers.set('Content-Security-Policy', cspDirectives);\n  response.headers.set('X-Content-Type-Options', 'nosniff');\n  response.headers.set('X-Frame-Options', 'DENY');\n  response.headers.set('X-XSS-Protection', '1; mode=block');\n  response.headers.set('Referrer-Policy', 'strict-origin-when-cross-origin');\n  response.headers.set('Permissions-Policy', 'camera=(), microphone=(), geolocation=()');\n  response.headers.set(\n    'Strict-Transport-Security',\n    'max-age=31536000; includeSubDomains; preload'\n  );\n  response.headers.set(\n    'Expect-CT',\n    'max-age=86400, enforce'\n  );\n\n  // Remove fingerprinting headers\n  response.headers.delete('X-Powered-By');\n  response.headers.delete('Server');\n\n  return response;\n}\n\nexport const config = {\n  matcher: [\n    '/((?!_next/static|_next/image|favicon.ico|.*\\\\.(?:svg|png|jpg|jpeg|gif|webp)$).*)',\n  ],\n};\n");
w("next.config.js", "/** @type {import('next').NextConfig} */\nconst nextConfig = {\n  eslint: {\n    ignoreDuringBuilds: true,\n  },\n  images: { unoptimized: true },\n\n  // ─── Headers de seguridad adicionales (refuerza middleware.ts) ───────────\n  async headers() {\n    return [\n      {\n        source: '/(.*)',\n        headers: [\n          { key: 'X-DNS-Prefetch-Control', value: 'on' },\n          { key: 'X-Content-Type-Options', value: 'nosniff' },\n          { key: 'X-Frame-Options', value: 'DENY' },\n          {\n            key: 'Strict-Transport-Security',\n            value: 'max-age=31536000; includeSubDomains; preload',\n          },\n          { key: 'Referrer-Policy', value: 'strict-origin-when-cross-origin' },\n          {\n            key: 'Permissions-Policy',\n            value: 'camera=(), microphone=(), geolocation=()',\n          },\n        ],\n      },\n    ];\n  },\n\n  // ─── Webpack: evitar que secrets se filtren al bundle del cliente ─────────\n  webpack(config, { isServer }) {\n    if (!isServer) {\n      // Asegurarse de que ningún módulo server-only llegue al cliente\n      config.resolve.fallback = {\n        ...config.resolve.fallback,\n        fs: false,\n        net: false,\n        tls: false,\n        crypto: false,\n      };\n    }\n    return config;\n  },\n};\n\nmodule.exports = nextConfig;\n");
